import * as React from "react";

export interface ExtendOfferStepProps {
	instanceId: string;
	state: string;
	onEvent: (event: string, payload?: Record<string, unknown>) => Promise<void> | void;
}

const FIELDS: ReadonlyArray<{ id: string; label: string; required: boolean; pii: boolean }> = [
	{ id: "base_salary", label: "Base salary", required: true, pii: false },
	{ id: "bonus_target", label: "Bonus target", required: false, pii: false },
	{ id: "start_date", label: "Proposed start", required: true, pii: false },
	{ id: "offer_expiry", label: "Offer expires", required: true, pii: false },
	{ id: "offer_letter", label: "Offer letter PDF", required: true, pii: true },
	{ id: "equity_units", label: "RSU units", required: false, pii: false },
];

/**
 * Minimal review step for the extend_offer workflow. Hosts wrap this with
 * the project-wide auth/tenant context — keeping the component dumb so
 * generated code stays portable across Next.js and plain Vite apps.
 */
export function ExtendOfferStep(props: ExtendOfferStepProps): React.ReactElement {
	const [busy, setBusy] = React.useState(false);

	const fire = React.useCallback(
		async (event: string) => {
			if (busy) return;
			setBusy(true);
			try {
				await props.onEvent(event, {});
			} finally {
				setBusy(false);
			}
		},
		[busy, props],
	);

	return (
		<section data-testid="extend_offer-step" aria-labelledby="extend_offer-step-title">
			<header>
				<h2 id="extend_offer-step-title">Extend an offer</h2>
				<p>State: <code>{props.state}</code></p>
				<p>Instance: <code>{props.instanceId}</code></p>
			</header>
			<dl>
				{FIELDS.map((field) => (
					<React.Fragment key={field.id}>
						<dt>{field.label}{field.required ? " *" : ""}{field.pii ? " (PII)" : ""}</dt>
						<dd>—</dd>
					</React.Fragment>
				))}
			</dl>
			<footer>
				<button type="button" disabled={busy} onClick={() => fire("submit")}>
					Submit
				</button>
				<button type="button" disabled={busy} onClick={() => fire("approve")}>
					Approve
				</button>
			</footer>
		</section>
	);
}
